#!/usr/bin/env python3
# -*- coding: utf-8 -*-
import base64
import subprocess
from pathlib import Path

GAMESALE_DIR = Path.home() / "Desktop" / "\u30b2\u30fc\u30e0\u30bb\u30fc\u30eb\u30b5\u30a4\u30c8" / "gamesale"

HTML_B64 = ""

def main():
    html = base64.b64decode(HTML_B64).decode("utf-8")
    index_path = GAMESALE_DIR / "index.html"
    with open(index_path, "w", encoding="utf-8") as f:
        f.write(html)
    print("index.html updated")
    import os
    os.chdir(GAMESALE_DIR)
    subprocess.run(["git", "add", "index.html"])
    r = subprocess.run(["git", "diff", "--staged", "--quiet"])
    if r.returncode != 0:
        subprocess.run(["git", "commit", "-m", "index.html update"])
        subprocess.run(["git", "push"])
        print("GitHub push done")
    else:
        print("No changes")

if __name__ == "__main__":
    main()
